/* ------------------------------------------------------------------ */
/* small building blocks                                                */
/* ------------------------------------------------------------------ */
function Fig({ src, alt, cap, zoomable = true }) {
  const [zoom, setZoom] = useState(false);
  return (
    <figure style={{ ...S.figure, cursor: zoomable ? "zoom-in" : "default" }}
      onClick={() => zoomable && setZoom(true)}>
      <img src={src} alt={alt} style={S.figImg} />
      {cap && <figcaption style={S.figCap}>{cap}</figcaption>}
      {zoom && (
        <div onClick={(e) => { e.stopPropagation(); setZoom(false); }}
          style={{
            position: "fixed", inset: 0, background: "rgba(0,0,0,0.88)",
            zIndex: 99, display: "flex", alignItems: "center",
            justifyContent: "center", cursor: "zoom-out", padding: 24,
          }}>
          <img src={src} alt={alt}
            style={{ maxWidth: "96vw", maxHeight: "94vh", objectFit: "contain" }} />
        </div>
      )}
    </figure>
  );
}

function T({ head, rows }) {
  return (
    <table style={S.table}>
      <thead><tr>{head.map((h, i) => <th key={i} style={S.th}>{h}</th>)}</tr></thead>
      <tbody>
        {rows.map((r, i) => (
          <tr key={i}>{r.map((c, j) => (
            <td key={j} style={{ ...S.td, ...(j > 0 ? S.mono : {}) }}>{c}</td>
          ))}</tr>
        ))}
      </tbody>
    </table>
  );
}

function Note({ children, color = C.warn, title = "Note" }) {
  return (
    <div style={S.callout(color)}>
      <strong style={{ color }}>{title}: </strong>{children}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* lesson                                                               */
/* ------------------------------------------------------------------ */
const SECTIONS = [
  ["intro", "Overview"], ["setup", "Scene Setup"], ["s1", "1 · Noise"],
  ["s2", "2 · Voronoi"], ["s3", "3 · Pointiness"], ["s4", "4 · Combine"],
  ["s5", "5 · Layer"], ["tree", "Full Tree"], ["tweak", "Tweaks & Fixes"],
];

export default function ProceduralWearLesson() {
  const [active, setActive] = useState("intro");
  const go = (id) => {
    setActive(id);
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  return (
    <div style={S.page}>
      <nav style={S.nav}>
        <div style={S.navInner}>
          {SECTIONS.map(([id, label]) => (
            <button key={id} style={S.navBtn(active === id)} onClick={() => go(id)}>
              {label}
            </button>
          ))}
        </div>
      </nav>

      <div style={S.wrap}>
        {/* ------------------------------------------------ hero */}
        <header id="intro" style={S.hero}>
          <div style={S.kicker}>Shader Editor · Procedural Texturing · Module A1</div>
          <h1 style={S.h1}>Procedural Wear Shader</h1>
          <p style={S.lede}>
            Build a fully procedural worn-paint material — organic patina, cellular
            rust pitting, chipped-paint cells and edge scraping — with wear
            boundaries defined entirely in the Shader Editor. No UV unwrap, no
            image textures, no baking: every mark is driven by Noise, Voronoi,
            Color Ramps and a Geometry ▸ Pointiness signal.
          </p>
          <div style={S.badges}>
            <span style={S.badge}>Blender 5.1</span>
            <span style={S.badge}>Cycles (required for Pointiness)</span>
            <span style={S.badge}>38 nodes · 5 steps</span>
            <span style={S.badge}>≈ 45 min</span>
          </div>
        </header>

        <Fig src={IMG.final} alt="Final procedural wear shader render"
          cap="The finished shader: teal paint with grime mottling, bare-metal scrapes on every exposed edge, orange rust creeping around the wear, chipped-paint cells and pin-point rust pitting. Rendered in Cycles — no image textures anywhere." />

        <div style={S.grid2}>
          <Fig src={IMG.before} alt="Plain paint before wear"
            cap="Before — a flat Principled BSDF with plain paint." />
          <Fig src={IMG.final} alt="After applying the wear shader"
            cap="After — the same objects with the procedural wear tree." />
        </div>

        <h3 style={S.h3}>How the shader thinks</h3>
        <p style={S.p}>
          Everything in this material reduces to <em>grayscale masks</em>. Textures
          generate raw signals (noise grain, cell patterns, edge curvature); Color
          Ramps convert those signals into masks by deciding where black ends and
          white begins; Math nodes combine masks; and the final masks drive Mix
          Color nodes that layer paint → rust → bare metal, plus Roughness,
          Metallic and Bump. The single most important idea:
          <strong> the Color Ramp <em>is</em> the wear boundary</strong> — a narrow
          ramp gives crisp edge scraping, a soft ramp gives gradual patina.
        </p>

        {/* ------------------------------------------------ setup */}
        <h2 id="setup" style={S.h2}><span style={S.stepNum}>0</span>Scene setup</h2>
        <p style={S.p}>
          Pointiness needs curvature to bite on, so the demo objects must have
          beveled or rounded edges and reasonable mesh density:
        </p>
        <T head={["Object", "Setup"]} rows={[
          ["Cube", "Bevel modifier: Width 0.12, Segments 4, Angle limit — then Subdivision Surface, 2 levels"],
          ["Suzanne", "Subdivision Surface, 2–3 levels, Shade Smooth"],
          ["Render engine", "Cycles (Pointiness outputs flat gray in EEVEE)"],
          ["Material", "One material, named ProceduralWear, assigned to both objects"],
        ]} />
        <Note color={C.warn} title="Why the bevels matter">
          Pointiness is a per-vertex curvature attribute. A hard-edged cube with no
          bevel has no vertices along its edges for the signal to live on — the mask
          will simply never appear. Bevel + subdivision gives the edge a strip of
          dense geometry where Pointiness can register.
        </Note>

        {/* ------------------------------------------------ step 1 */}
        <h2 id="s1" style={S.h2}><span style={S.stepNum}>1</span>Patina noise — fBM grain</h2>
        <p style={S.p}>
          Add <strong>Texture ▸ Noise Texture</strong>. In Blender 5.1 there is no
          standalone Musgrave node — the Musgrave fractal types live inside the
          Noise Texture under the <strong>Type</strong> dropdown:
          <span style={S.mono}> fBM · Multifractal · Hybrid Multifractal · Ridged
          Multifractal · Hetero Terrain</span>. Pick <strong>fBM</strong> for
          classic layered grain. Feed it from
          <span style={S.mono}> Texture Coordinate ▸ Object → Mapping</span> so the
          pattern sticks to the object and survives transforms.
        </p>
        <Fig src={IMG.tree1} alt="Step 1 node diagram"
          cap="Step 1 nodes — exact values from the working file. Dimmed nodes are neighbours from later steps; the ramp's Color output fans out to five of them." />
        <T head={["Node", "Setting", "Value"]} rows={[
          ["Noise Texture", "Type", "fBM"],
          ["", "Scale", "5.5"],
          ["", "Detail", "8.0"],
          ["", "Roughness", "0.55"],
          ["Color Ramp (Patina)", "Stops", "black @ 0.32 → white @ 0.68 (Linear)"],
        ]} />
        <Fig src={IMG.patina} alt="Patina mask render"
          cap="The patina mask visualised on the objects (wire the ramp into an Emission shader to preview any mask like this). The wide 0.32→0.68 ramp keeps soft gray transitions — this is the “soft ramp = gradual patina” half of the rule." />

        {/* ------------------------------------------------ step 2 */}
        <h2 id="s2" style={S.h2}><span style={S.stepNum}>2</span>Voronoi — rust pits &amp; chip cells</h2>
        <p style={S.p}>
          Two Voronoi Textures at very different scales produce the two cellular
          effects. The <strong>pits</strong> use the <span style={S.mono}>Distance</span> output:
          near a cell centre distance ≈ 0, so an <em>inverted, narrow</em> ramp
          (white @ 0.05 → black @ 0.16) turns each cell centre into a tiny white
          dot — rust pitting. The <strong>chips</strong> use the
          <span style={S.mono}> Color</span> output, which assigns a random flat
          color per cell; run it through a <strong>Constant</strong>-interpolation
          ramp with the white stop at 0.72 and roughly the brightest quarter of
          cells become solid-white islands — chipped paint flakes with hard edges.
        </p>
        <Fig src={IMG.tree2} alt="Step 2 node diagram"
          cap="Step 2 — both Voronois share the same Mapping vector. Note Constant interpolation on the chip ramp: that is what makes chip borders razor-sharp." />
        <T head={["Node", "Setting", "Value"]} rows={[
          ["Voronoi (Pits)", "Feature / Scale", "F1 / 38.0"],
          ["Color Ramp (Pits)", "Stops", "white @ 0.05 → black @ 0.16 (inverted, narrow)"],
          ["Voronoi (Chips)", "Feature / Scale", "F1 / 10.0"],
          ["Color Ramp (Chips)", "Stops", "black @ 0.0 → white @ 0.72, Interpolation: Constant"],
        ]} />
        <div style={S.grid2}>
          <Fig src={IMG.pits} alt="Pit mask render"
            cap="Pit mask — thousands of pin-point dots from the narrow inverted ramp." />
          <Fig src={IMG.chips} alt="Chip cells mask render"
            cap="Chip mask — random Voronoi cells thresholded to hard islands." />
        </div>

        {/* ------------------------------------------------ step 3 */}
        <h2 id="s3" style={S.h2}><span style={S.stepNum}>3</span>Pointiness — the edge signal</h2>
        <p style={S.p}>
          Add <strong>Input ▸ Geometry</strong> and use its
          <strong> Pointiness</strong> output: a curvature attribute that reads
          ≈ 0.5 on flat surfaces, <em>slightly above</em> on convex edges and
          <em> slightly below</em> in concave crevices. Split it through three
          ramps to get three masks: a <strong>crisp edge mask</strong> (scraping),
          a <strong>broad edge mask</strong> (gates the chips and the rust halo),
          and an <strong>inverted cavity mask</strong> (rust collecting in
          recesses).
        </p>
        <Note color="#E76F51" title="The #1 Pointiness gotcha">
          The usable signal lives in a razor-thin band around 0.5 — on this scene
          the measured range was roughly <span style={S.mono}>0.47 – 0.52</span>.
          Ramp stops like 0.4→0.6 will give you an all-black or all-white mask.
          Start both stops within a few hundredths of 0.5 and nudge while watching
          a preview. To measure your own mesh: wire Pointiness → Emission →
          Material Output and render — mid-gray is your centre, the bright rims are
          your white stop.
        </Note>
        <Fig src={IMG.tree3} alt="Step 3 node diagram"
          cap="One Pointiness output, three ramps. Stop positions are precise on purpose — they were measured from a render of the raw signal." />
        <T head={["Ramp", "Stops", "Purpose"]} rows={[
          ["Edge (crisp)", "black @ 0.5089 → white @ 0.521", "hard scrape boundary on exposed edges"],
          ["Edge (broad)", "black @ 0.503 → white @ 0.521", "soft falloff; gates chips + rust halo"],
          ["Cavity (inverted)", "white @ 0.4678 → black @ 0.4969", "concave recesses where rust collects"],
        ]} />
        <div style={S.grid2}>
          <Fig src={IMG.edge} alt="Crisp edge mask render"
            cap="Crisp edge mask — white exactly on the cube bevels and Suzanne's brow, ears and nose ridges." />
          <Fig src={IMG.edgeBroad} alt="Broad edge mask render"
            cap="Broad edge mask — same signal, wider ramp: a soft halo spreading in from every edge." />
        </div>

        {/* ------------------------------------------------ step 4 */}
        <h2 id="s4" style={S.h2}><span style={S.stepNum}>4</span>Combine the masks</h2>
        <p style={S.p}>
          Math nodes turn the raw masks into two final signals. Read multiply as
          “AND” (both must be present) and maximum as “OR” (either one):
        </p>
        <T head={["Result", "Formula", "Math nodes"]} rows={[
          ["Scrape", "Edge(crisp) × Patina", "Multiply"],
          ["Chips", "ChipCells × Edge(broad)", "Multiply"],
          ["WEAR", "max(Scrape, Chips) → Harden Ramp 0.22→0.50", "Maximum + Color Ramp"],
          ["Rust base", "max(Cavity × Patina, Pits)", "Multiply + Maximum"],
          ["Rust ring", "clamp(Edge(broad) × Patina − WEAR)", "Multiply + Subtract (Clamp ✓)"],
          ["RUST", "max(base, ring) → Harden Ramp 0.12→0.42", "Maximum (Clamp ✓) + Color Ramp"],
        ]} />
        <p style={S.p}>
          Multiplying the edge mask by the patina noise breaks the scrape line into
          organic bites instead of a uniform stripe. The <em>rust ring</em> is the
          clever part: broad-edge minus the wear mask leaves only a halo
          <em> around</em> the scrapes — exactly where real rust creeps out from
          damaged paint. Both final masks then pass through one more
          <strong> hardening Color Ramp</strong>, which squeezes mid-gray mush into
          confident boundaries — the “narrow ramp = crisp edge” half of the rule,
          applied at the mask level.
        </p>
        <Fig src={IMG.tree4} alt="Step 4 node diagram"
          cap="The combine stage. Inputs from steps 1–3 arrive on the left (dimmed); the two hardened outputs feed everything in step 5." />
        <div style={S.grid2}>
          <Fig src={IMG.wear} alt="Combined wear mask render"
            cap="WEAR mask after hardening — scrapes hug the edges, chips cluster near them." />
          <Fig src={IMG.rust} alt="Combined rust mask render"
            cap="RUST mask after hardening — pits everywhere, halos around the wear." />
        </div>

        {/* ------------------------------------------------ step 5 */}
        <h2 id="s5" style={S.h2}><span style={S.stepNum}>5</span>Layer the materials</h2>
        <p style={S.p}>
          Two chained <strong>Mix Color</strong> nodes stack the layers in
          real-world order — paint first, rust eats the paint, bare metal is
          scraped through everything:
        </p>
        <T head={["Node", "A input", "B input", "Factor"]} rows={[
          ["Paint + Grime", <span><i style={S.swatch("#1A6472")} />grimy teal 0.010/0.130/0.158</span>,
            <span><i style={S.swatch("#26808F")} />clean teal 0.021/0.212/0.250</span>, "Patina ramp"],
          ["Rust Color", <span><i style={S.swatch("#3B1405")} />dark brown 0.130/0.041/0.013</span>,
            <span><i style={S.swatch("#B26232")} />orange 0.448/0.137/0.028</span>, "Noise Fac (mottling)"],
          ["Mix: Paint → Rust", "Paint+Grime result", "Rust Color result", "RUST mask"],
          ["Mix: → Bare Metal", "previous result", <span><i style={S.swatch("#93969B")} />steel 0.301/0.312/0.330</span>, "WEAR mask"],
        ]} />
        <p style={S.p}>The same two masks drive the surface response:</p>
        <T head={["BSDF input", "Wiring"]} rows={[
          ["Base Color", "Mix: → Bare Metal · Result"],
          ["Metallic", "WEAR mask (scrapes become metal, paint stays dielectric)"],
          ["Roughness", "Mix Float chain: 0.45 paint → 0.85 rust (RUST mask) → 0.30 metal (WEAR mask)"],
          ["Normal", "Bump ← Height = Pits + Chips · Invert ✓ · Strength 0.35"],
        ]} />
        <Fig src={IMG.tree5} alt="Step 5 node diagram"
          cap="The layering stage: color chain on top, roughness chain in the middle, bump chain below — all converging on the Principled BSDF." />
        <Fig src={IMG.final} alt="Final render"
          cap="Result: every wear phenomenon lands where physics says it should — scrapes on edges, rust around scrapes and in pits, grime in the patina, and the bump dents the pits and chips." />

        {/* ------------------------------------------------ full tree */}
        <h2 id="tree" style={S.h2}><span style={S.stepNum}>✓</span>The complete tree</h2>
        <p style={S.p}>
          All 38 nodes. The frames match the five steps of this lesson — rebuild it
          frame by frame and preview every mask through an Emission shader before
          moving on. Click to zoom.
        </p>
        <Fig src={IMG.treeFull} alt="Complete node tree diagram"
          cap="ProceduralWear — complete node tree. Signal flow: coordinates → textures → ramps → mask math → layered mixing → Principled BSDF." />

        {/* ------------------------------------------------ tweaks */}
        <h2 id="tweak" style={S.h2}><span style={S.stepNum}>⚙</span>Tweaks &amp; troubleshooting</h2>
        <h3 style={S.h3}>Dial the look</h3>
        <T head={["You want…", "Change"]} rows={[
          ["More / less overall wear", "Slide the Harden Ramp (wear) stops left / right"],
          ["Wider rust creep", "Lower the Edge (broad) black stop toward 0.50"],
          ["Bigger paint chips", "Voronoi Chips scale 10 → 6; fewer chips: raise chip ramp stop 0.72 → 0.8"],
          ["Coarser / finer patina", "Noise scale 5.5 (lower = blotchier), Detail 8"],
          ["Denser pitting", "Voronoi Pits scale 38 → 60; larger pits: widen 0.05–0.16 ramp"],
          ["Different paint", "Swap both colors in Paint + Grime (keep B brighter than A)"],
        ]} />
        <h3 style={S.h3}>When it goes wrong</h3>
        <T head={["Symptom", "Cause → Fix"]} rows={[
          ["Edge mask fully black or white", "Ramp stops outside the real Pointiness band → render Pointiness through Emission, re-centre stops near 0.5"],
          ["No edge wear at all in EEVEE", "Pointiness is Cycles-only → switch engine, or bake an AO/curvature map instead"],
          ["Wear ignores small details", "Pointiness is vertex-based → add subdivision or bevel segments where you need wear"],
          ["Chips everywhere instead of near edges", "Chips must be multiplied by the broad edge mask, not used raw"],
          ["Texture swims when object moves", "Use Object coordinates from Texture Coordinate, not Generated/UV"],
          ["Boundaries look muddy", "Tighten the two Harden Ramps — mask contrast, not color, sells the effect"],
        ]} />

        <div style={{ ...S.callout(C.teal), marginTop: 40 }}>
          <strong style={{ color: C.teal }}>Wrap-up: </strong>
          The pattern you just built — <em>signal → ramp → combine → layer</em> —
          is the backbone of almost every procedural material. Swap the signals
          (AO, vertex colors, baked curvature) or the layers (dust, moss, scorch)
          and the same 5-step skeleton produces an entirely different surface
          story. Ramp width is always the boundary control: narrow = crisp
          scraping, soft = gradual patina.
        </div>

        <p style={{ ...S.p, color: C.dim, fontSize: 13, marginTop: 30 }}>
          Built and verified in Blender 5.1.1 / Cycles (Metal GPU). All node
          values, ramp positions and renders in this lesson were captured from the
          working file <span style={S.mono}>procedural_wear_lesson.blend</span>.
        </p>
        <LegalDisclaimer style={{ marginTop: 48 }} />
      </div>
    </div>
  );
}
